const d = $json.body || $json;

if (!d.email || !d.full_name) throw new Error('Missing email or full_name in payload');

const emailBody = `
<!DOCTYPE html>
<html>
<head>
  <style>
    body { font-family: Arial, sans-serif; line-height: 1.6; color: #333; background: #f4f4f4; margin: 0; padding: 0; }
    .container { max-width: 640px; margin: 20px auto; background: white; border-radius: 8px; overflow: hidden; box-shadow: 0 4px 6px rgba(0,0,0,0.1); }
    .header { background: #000000; color: white; padding: 40px 30px; text-align: center; }
    .header h1 { margin: 0 0 10px 0; font-size: 28px; font-weight: 900; letter-spacing: 2px; }
    .header p { margin: 0; font-size: 14px; opacity: 0.7; }
    .content { padding: 40px 30px; }
    .id-box { background: #f0f9ff; border: 2px solid #0ea5e9; border-radius: 6px; padding: 20px; margin: 24px 0; text-align: center; }
    .id-box p { margin: 4px 0; font-size: 14px; color: #555; }
    .id-box strong { font-size: 22px; color: #0369a1; letter-spacing: 1px; font-family: monospace; }
    .steps { background: #f9f9f9; border-radius: 6px; padding: 20px 20px 20px 36px; margin: 20px 0; }
    .steps li { margin-bottom: 10px; font-size: 14px; }
    .cta-button { display: inline-block; background: #000000; color: white; padding: 14px 36px; text-decoration: none; border-radius: 5px; font-weight: bold; font-size: 15px; margin: 20px 0; }
    .footer { background: #f0f0f0; padding: 20px; text-align: center; font-size: 12px; color: #888; }
  </style>
</head>
<body>
  <div class="container">
    <div style="background:#ffffff;padding:18px 30px;text-align:center;border-bottom:2px solid #f0f0f0"><img src="https://cargolink.sa/cargolink.png" alt="CargoLink" style="height:52px;width:auto;display:block;margin:0 auto" /></div><div class="header">
      <h1>CargoLink</h1>
      <p>Freight Marketplace · Welcome Aboard</p>
    </div>
    <div class="content">
      <p style="font-size: 16px; font-weight: 700;">Hello ${d.full_name},</p>
      <p>Your CargoLink account has been created. You can now post freight requests and receive competitive quotes from verified forwarders worldwide.</p>

      <div class="id-box">
        <p>Your Account ID</p>
        <strong>${d.sovereign_id || 'Assigned on first login'}</strong>
        <p style="margin-top: 8px; font-size: 12px; color: #888;">Keep this ID for reference when contacting support.</p>
      </div>

      <h3 style="color: #111; font-size: 15px;">Getting Started</h3>
      <ol class="steps">
        <li>Log in to your <a href="https://cargolink.sa/dashboard" style="color: #0369a1;">Dashboard</a>.</li>
        <li>Post your first freight request with origin, destination, and cargo details.</li>
        <li>Receive quotes from multiple verified forwarders within hours.</li>
        <li>Compare quotes and open a chat to negotiate directly before booking.</li>
      </ol>

      <div style="text-align: center;">
        <a href="https://cargolink.sa/dashboard" class="cta-button">Go to Dashboard →</a>
      </div>

      <p style="font-size: 13px; color: #666; margin-top: 30px;">Questions? Reply to this email or visit <a href="https://cargolink.sa/contact" style="color: #0369a1;">cargolink.sa/contact</a>.</p>
    </div>
    <div class="footer">
      <p><strong>CargoLink Platform</strong> — Connecting shippers with the world's best freight forwarders</p>
      <p>© 2025 CargoLink. All rights reserved.</p>
    </div>
  </div>
</body>
</html>`;

return {
  json: {
    email: d.email,
    full_name: d.full_name,
    company_name: d.company_name || '',
    sovereign_id: d.sovereign_id || '',
    email_body: emailBody
  }
};
